588	// SynthesizeCommit stages real file changes, explicitly excluding harness noise
589	// paths, and creates a commit with msg as the commit message. Returns (true, nil)
590	// when a commit was made, (false, nil) when nothing real remained to commit
591	// after exclusions, and (false, err) on failure.
592	func (r *RealGitOps) SynthesizeCommit(dir, msg string) (bool, error) {
593		// Do NOT list already-gitignored paths (.ddx/agent-logs, .ddx/workers) as
594		// :(exclude) pathspecs. Git treats a path named by :(exclude) as explicitly
595		// referenced, so when the path is also .gitignored git emits "The following
596		// paths are ignored by one of your .gitignore files" AND exits 1 — even
597		// though the pathspec is trying to SKIP it. Paths already in .gitignore are
598		// excluded by default; excludes here are only for paths that would
599		// otherwise be tracked.
600		addArgs := []string{
601			"add", "-A", "--",
602			".",
603		}
604		addArgs = append(addArgs, synthesizeCommitExcludePathspecs(dir)...)
605		if err := internalgit.Command(context.Background(), dir, addArgs...).Run(); err != nil {
606			return false, fmt.Errorf("staging changes: %w", err)
607		}
608		statusOut, _ := internalgit.Command(context.Background(), dir, "diff", "--cached", "--name-only").Output()
609		if len(bytes.TrimSpace(statusOut)) == 0 {
610			return false, nil
611		}
612		if msg == "" {
613			msg = "chore: execute-bead synthesized result commit"
614		}
615		out, err := internalgit.Command(context.Background(), dir, "commit", "-m", msg).CombinedOutput()
616		if err != nil {
617			return false, fmt.Errorf("synthesize commit: %s: %w", strings.TrimSpace(string(out)), err)
618		}
619		return true, nil
620	}
